import{_ as o,o as t,c as i,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Platform Shell","description":"","frontmatter":{},"headers":[],"relativePath":"epics/platform-shell.md","filePath":"epics/platform-shell.md"}'),r={name:"epics/platform-shell.md"};function n(a,e,d,l,c,p){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="epic-platform-shell" tabindex="-1">Epic: Platform Shell <a class="header-anchor" href="#epic-platform-shell" aria-label="Permalink to &quot;Epic: Platform Shell&quot;">​</a></h1><blockquote><p>The Sovereign Core — the Next.js runtime host, middleware, shell modes, and SDK bridge that every plugin runs inside.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Platform Shell is the runtime that composes plugins into a coherent experience. It owns the sidebar chrome, the three shell modes (<code>default</code>, <code>overlay</code>, <code>minimal</code>), request authentication, CSP/security headers, the cross-plugin data sharing mechanism, and the SDK host implementation that bridges plugin code to platform services. Once this epic completed, all subsequent work is either new features layered on top or hardening of what the shell provides.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-2-1-—-runtime-scaffold" tabindex="-1">✅ 2.1 — Runtime scaffold <a class="header-anchor" href="#✅-2-1-—-runtime-scaffold" aria-label="Permalink to &quot;✅ 2.1 — Runtime scaffold&quot;">​</a></h4><p><strong>Goal:</strong> Sovereign Core Next.js app scaffold with shell layout, middleware, and root placeholder page. No plugins wired yet.</p><p><strong>Deliverables:</strong></p><ul><li><code>runtime/</code> — Next.js 15 app with App Router: <ul><li><code>app/(platform)/layout.tsx</code> — shell layout implementing the three-section sidebar (PLT-11): <ul><li><strong>Top:</strong> branding header — logo / tenant name; links to <code>/</code>.</li><li><strong>Middle:</strong> plugin icon area. In the v0.3 scaffold this section is empty (no plugins installed yet). The first icon will always be the root plugin, pointing to <code>/</code> (PLT-12); it is inserted and populated in Tasks 0.4.05 (Launcher) and 0.4.04 (root plugin config). Each icon loads from the manifest <code>icon</code> field (path relative to plugin root); runtime generates a two-letter monogram fallback if <code>icon</code> is absent.</li><li><strong>Bottom:</strong> hardcoded shell chrome, <strong>not</strong> driven by the plugin registry — Console icon (rendered only for <code>platform:admin</code>) + Account avatar slot (all authenticated users). This section does not participate in user customisation.</li><li>Mobile layout: header (logo + Account avatar) + content area + footer launcher (mirrors middle section; Console icon visible to admin only).</li></ul></li><li><code>app/(platform)/page.tsx</code> — placeholder redirect page (empty for now; in Task 0.4.04 this redirects to the configured root plugin&#39;s <code>routePrefix</code>)</li><li><code>app/plugins/</code> — empty directory with <code>.gitignore</code> (generated, never committed)</li><li><code>src/middleware.ts</code> — reads session cookie, calls <code>apps/auth /api/verify</code> to validate session (v0.3 approach — see SRS AUTH-05 for v0.5 local verification target), redirects to <code>/login</code> if unauthenticated</li><li><code>src/registry.ts</code> — reads <code>generated/registry.ts</code>, exports installed plugin list</li><li><code>generated/registry.ts</code> — placeholder empty registry</li><li><code>app/login/route.ts</code> — redirects unauthenticated users to the auth server&#39;s login page (the login/registration UI lives in <code>apps/auth</code>, not the runtime; SRS §3.3). The auth server redirects back after login.</li></ul></li><li><code>runtime/next.config.ts</code> — must include: <ul><li><code>transpilePackages: [&#39;@sovereignfs/sdk&#39;, &#39;@sovereignfs/ui&#39;, &#39;@sovereignfs/db&#39;, &#39;@sovereignfs/manifest&#39;, &#39;@sovereignfs/mailer&#39;]</code> — compiles all workspace package TypeScript sources directly during dev. Changes to any package file trigger HMR in the runtime without a separate watch build. (All packages share the single <code>@sovereignfs/*</code> scope; only <code>sdk</code> and <code>ui</code> are published, the rest are <code>private</code>.)</li><li><code>webpack: (config) =&gt; { config.resolve.symlinks = false; return config; }</code> — required for plugin HMR. Without this, webpack resolves symlinks to their real path before watching, breaking hot reload for plugin source files that are symlinked into <code>runtime/app/plugins/</code> by the generate script. Setting <code>symlinks: false</code> makes webpack watch the symlink path so edits to <code>plugins/[id]/app/</code> propagate via HMR immediately.</li></ul></li><li><code>runtime/package.json</code> — <code>dev</code> script runs the generate script before starting the dev server: <code>tsx ../scripts/generate-registry.ts &amp;&amp; next dev</code>. The generate script is run synchronously on startup (creates/updates symlinks), then Next.js dev server starts.</li><li>Environment: <code>SOVEREIGN_AUTH_URL</code>, <code>SOVEREIGN_AUTH_SECRET</code></li></ul><p><strong>SRS reference:</strong> 3.4 Runtime Layer, 3.10 Shared Login State, PLT-01, PLT-02, PLT-08, PLT-11, PLT-12, PLT-13</p><p><strong>Review checklist:</strong></p><ul><li>Unauthenticated request to <code>/</code> redirects to <code>/login</code></li><li>Shell renders correctly on desktop and mobile viewports</li><li><code>app/plugins/</code> is gitignored</li><li>No hardcoded auth secret</li><li>Editing a file in <code>packages/ui/src/</code> while <code>pnpm dev</code> is running triggers HMR in the runtime without any manual rebuild step</li><li>Editing a file in <code>plugins/console/app/</code> triggers HMR in the runtime</li></ul><hr><h4 id="✅-2-2-—-generate-script" tabindex="-1">✅ 2.2 — Generate script <a class="header-anchor" href="#✅-2-2-—-generate-script" aria-label="Permalink to &quot;✅ 2.2 — Generate script&quot;">​</a></h4><p><strong>Goal:</strong> Pre-build script that reads plugin manifests, validates them, and injects plugin routes into the runtime.</p><p><strong>Deliverables:</strong></p><ul><li><code>scripts/generate-registry.ts</code>: <ul><li>Scans <code>plugins/*/manifest.json</code></li><li>Validates each manifest via <code>packages/manifest</code></li><li>Fails with a clear error if any manifest is invalid</li><li>Writes <code>runtime/generated/registry.ts</code> — typed array of installed plugin manifests</li><li>In <code>development</code> mode: symlinks <code>plugins/[id]/app/</code> → <code>runtime/app/plugins/[id]/</code></li><li>In <code>production</code> mode: copies <code>plugins/[id]/app/</code> → <code>runtime/app/plugins/[id]/</code></li><li>Mode determined by <code>NODE_ENV</code></li><li><code>--watch</code> flag: when passed, watches the <code>plugins/</code> directory for new or removed plugin directories and re-runs the symlink/copy step automatically. Used by <code>runtime/package.json</code>&#39;s <code>dev</code> script to keep the plugin route tree in sync while the Next.js dev server is running. A newly added plugin directory is symlinked immediately; developers may need to trigger a route refresh in Next.js (fast-refresh boundary), but no manual generate command is needed.</li></ul></li><li><code>turbo.json</code> updated with two additions: <ul><li><code>generate</code> task: <code>dependsOn: [&quot;packages/manifest#build&quot;]</code>, outputs <code>[&quot;runtime/app/plugins/**&quot;, &quot;runtime/generated/**&quot;]</code>, <code>cache: false</code> (plugin file state is not cacheable)</li><li><code>runtime#build</code> override: <code>dependsOn: [&quot;generate&quot;, &quot;^build&quot;]</code> — ensures generate runs and all package deps are built before the runtime Next.js build starts. Without this, <code>next build</code> may run before plugins are composed in.</li></ul></li><li><code>package.json</code> script: <code>&quot;generate&quot;: &quot;tsx scripts/generate-registry.ts&quot;</code></li></ul><p><strong>SRS reference:</strong> 3.9 Plugin Loading Model</p><p><strong>Review checklist:</strong></p><ul><li>Invalid manifest causes script to exit non-zero with a readable error</li><li><code>runtime/generated/registry.ts</code> is valid TypeScript after running</li><li>Symlinks created in dev mode, copies in production mode</li><li>Running generate with no plugins produces an empty registry without errors</li></ul><hr><h4 id="✅-2-3-—-sdk-implementations-db-and-platform" tabindex="-1">✅ 2.3 — SDK implementations (db and platform) <a class="header-anchor" href="#✅-2-3-—-sdk-implementations-db-and-platform" aria-label="Permalink to &quot;✅ 2.3 — SDK implementations (db and platform)&quot;">​</a></h4><p><strong>Goal:</strong> Complete remaining SDK implementations. <code>sdk.auth</code> and <code>sdk.mailer</code> were wired in Task 0.4.02. This task completes <code>sdk.db</code> and <code>sdk.platform</code>.</p><blockquote><p><strong>Scope update (Jun 2026).</strong> Since this task was written the architecture moved on: <code>sdk.platform</code> and <code>sdk.mailer</code> are implemented <strong>directly in <code>packages/sdk</code></strong> (via <code>@sovereignfs/db</code>/<code>@sovereignfs/mailer</code>), not re-exported from the runtime — so the &quot;SDK re-exports runtime implementations&quot; deliverable below is obsolete, and <code>runtime/src/sdk/*</code> is not created. <code>sdk.platform.getConfig()</code> landed async with Task 0.5.03; this task completes the last stub, <code>sdk.db.getClient()</code> (async, returns the live platform Drizzle instance). The <strong>local JWT-verification middleware migration (AUTH-05) is split into its own follow-up task</strong> — it is large and security-sensitive (better-auth currently uses DB-backed session cookies with no JWT/cookie-cache configured; it needs auth-side JWT issuance plus Edge-compatible <code>jose</code> verification on the runtime), and the current <code>/api/verify</code> round-trip works correctly in the meantime.</p></blockquote><p><strong>Deliverables:</strong></p><ul><li><code>runtime/src/sdk/db.ts</code> — real <code>getClient()</code> returning scoped Drizzle instance</li><li><code>runtime/src/sdk/platform.ts</code> — real <code>getConfig()</code> reading from <code>tenants</code> table</li><li><code>runtime/src/middleware.ts</code> — updated to verify JWT locally using <code>SOVEREIGN_AUTH_SECRET</code> (replaces <code>/api/verify</code> round-trip per SRS AUTH-05)</li><li>SDK package updated to re-export all runtime implementations when running inside runtime context</li></ul><p><strong>SRS reference:</strong> 3.6 SDK</p><p><strong>Review checklist:</strong></p><ul><li><code>sdk.auth.requireSession()</code> throws when called from an unauthenticated context</li><li><code>sdk.db.getClient()</code> returns a working Drizzle instance</li><li><code>sdk.mailer.send()</code> delegates correctly to packages/mailer</li><li>No stub implementations remain for the v1 SDK surface</li></ul><hr><h4 id="✅-2-4-—-public-api-namespace-delegation" tabindex="-1">✅ 2.4 — Public <code>/api</code> namespace delegation <a class="header-anchor" href="#✅-2-4-—-public-api-namespace-delegation" aria-label="Permalink to &quot;✅ 2.4 — Public `/api` namespace delegation&quot;">​</a></h4><p><strong>Goal:</strong> Reserve the top-level <code>/api/*</code> namespace for plugin-served public APIs, per PLT-16. Required before the API Composer plugin (<code>docs/plugins/api-composer.md</code>) can serve its generated APIs.</p><p><strong>Deliverables:</strong></p><ul><li>Runtime middleware: requests under <code>/api/*</code> are exempt from the session-redirect rule (PLT-02) — the serving plugin owns authentication for these routes (API keys per the API Composer spec)</li><li>Route delegation: the runtime rewrites <code>/api/&lt;segment&gt;/*</code> to the registered API-provider plugin&#39;s serve route (for API Composer: <code>/api-composer/serve/&lt;segment&gt;/*</code>)</li><li>Provider registration mechanism — likely a manifest flag (e.g. <code>apiProvider</code>); exact shape decided in this task, coordinated with <code>packages/manifest</code>. Exactly one provider per instance in v1; the generate script fails loudly if two plugins declare it</li><li>With no provider installed, <code>/api/*</code> returns 404</li></ul><p><strong>SRS reference:</strong> PLT-16, <code>docs/plugins/api-composer.md</code> (architecture — <code>/api</code> namespace delegation)</p><p><strong>Review checklist:</strong></p><ul><li>An unauthenticated request under <code>/api/*</code> is not redirected to login</li><li><code>/api/&lt;slug&gt;/&lt;path&gt;</code> reaches the provider plugin&#39;s serve handler with the slug and path intact</li><li><code>/api/*</code> returns 404 when no provider plugin is installed</li><li>Two plugins declaring the provider flag fail the generate step with a clear error</li></ul><hr><h4 id="✅-2-5-—-overlay-shell-mode" tabindex="-1">✅ 2.5 — Overlay shell mode <a class="header-anchor" href="#✅-2-5-—-overlay-shell-mode" aria-label="Permalink to &quot;✅ 2.5 — Overlay shell mode&quot;">​</a></h4><p><strong>Goal:</strong> Add the <code>overlay</code> shell mode from RFC 0001 (SRS §3.8/§3.9) — a plugin renders as a dismissable dialog over the current page, with a full-page fallback on hard navigation — and migrate Console and Account to it. A v0.5 polish item; no hard dependency on the other v0.5 tasks, but it needs the <code>packages/ui</code> <code>Dialog</code> primitive. Console and Account already ship as <code>default</code>/full-page, so this is a retrofit.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/manifest</code>: <code>shell</code> enum gains <code>&#39;overlay&#39;</code>; tests; <strong>minor</strong> version bump</li><li><code>packages/ui</code>: a <code>Dialog</code> primitive (scrim + panel, sizes, Esc/scrim-click dismissal, focus trap, <code>--sv-*</code> tokens) and its mobile full-screen sheet behaviour</li><li>Runtime: a <code>@modal</code> parallel-route slot under <code>(platform)/</code> (<code>default.tsx</code>, dialog <code>layout.tsx</code>); the platform layout renders the slot</li><li><code>scripts/generate-registry.ts</code>: for <code>shell: overlay</code>, compose the plugin&#39;s <code>app/</code> tree twice — interception copy under <code>(platform)/@modal/(.)&lt;routePrefix&gt;/</code> and full-page fallback under <code>(platform)/(plugins)/&lt;routePrefix&gt;/</code>; emit the mode in the registry</li><li>Root-plugin eligibility (CON-11) excludes <code>overlay</code> plugins</li><li>Migrate <code>plugins/console</code> and <code>plugins/account</code> manifests to <code>shell: &quot;overlay&quot;</code>; update <code>docs/plugins/console.md</code> and <code>docs/plugins/account.md</code></li><li><code>CLAUDE.md</code>: hard-rule note that the shell route-group mapping gains the overlay compose target</li></ul><p><strong>SRS reference:</strong> RFC 0001, SRS §3.8, §3.9, CON-11, §5</p><p><strong>Review checklist:</strong></p><ul><li>A soft (in-app) navigation to Console/Account opens it as a dialog over the current page; the underlying page stays mounted and is restored on dismiss</li><li>A hard load / deep link / refresh of <code>/console</code> or <code>/account</code> renders the full-page fallback</li><li><code>adminOnly</code> gating still returns 403 for Console regardless of presentation mode</li><li>Esc and scrim-click dismiss the dialog; mobile renders a full-screen sheet</li><li>An <code>overlay</code> plugin cannot be selected as the root plugin (CON-11)</li><li>The generate script composes both copies; navigating between an overlay plugin&#39;s sub-routes stays within the dialog</li></ul><hr><h4 id="✅-2-6-—-cross-plugin-data-sharing-consent-gated" tabindex="-1">✅ 2.6 — Cross-plugin data sharing (consent-gated) <a class="header-anchor" href="#✅-2-6-—-cross-plugin-data-sharing-consent-gated" aria-label="Permalink to &quot;✅ 2.6 — Cross-plugin data sharing (consent-gated)&quot;">​</a></h4><p><strong>Goal:</strong> Implement the consent-gated, pull-based, read-only cross-plugin data-sharing mechanism specified in RFC 0002 / SRS §3.13. The reserved <code>sdk.data</code> surface and the <code>data:provide</code>/<code>data:consume</code> permissions already exist as stubs; this task makes them real. Depends on <code>sdk.db</code> (Task 0.5.05).</p><p><strong>Delivered:</strong></p><ul><li><code>@sovereignfs/manifest</code> → 0.10.0: optional <code>data.provides[]</code> / <code>data.consumes[]</code> manifest fields; <code>data:provide</code> and <code>data:consume</code> permissions promoted from reserved to active</li><li><code>@sovereignfs/db</code> → 0.8.0: <code>consent_grants</code> and <code>data_access_log</code> tables (SQLite + Postgres, bootstrap DDL, dialect-parity-tested); 7 helper functions (<code>getConsentGrant</code>, <code>listConsentGrants</code>, <code>listAllConsentGrants</code>, <code>createConsentGrant</code>, <code>revokeConsentGrant</code>, <code>logDataAccess</code>)</li><li><code>@sovereignfs/sdk</code> → 1.2.0: <code>sdk.data.provide(contract, resolver)</code> stores an in-process resolver via the host; <code>sdk.data.query(ref, params)</code> consent-checks, calls the resolver, and logs access; <code>SdkHost</code> extended with <code>data</code> section</li><li>Runtime → 0.13.0: in-memory resolver registry; middleware injects <code>x-sovereign-plugin-id</code> for plugin routes; <code>GET/POST /api/account/data-grants</code>, <code>DELETE /api/account/data-grants/[id]</code>, <code>GET /api/admin/data-grants</code></li><li>Account plugin → 0.3.0: <strong>Data</strong> tab — lists active consents with per-grant revoke</li><li><code>docs/plugin-development.md</code>: <code>data</code> manifest field documented, <code>sdk.data</code> usage guide with provider/consumer code samples; docs-parity test passes</li></ul><p><strong>Deferred:</strong> <code>packages/ui</code> <code>ConsentPrompt</code> dialog primitive and Console data oversight view are post-task refinements; the grant management API is fully functional and the Account tab provides user-facing revocation.</p><p><strong>SRS reference:</strong> RFC 0002, SRS §3.13, §5 (manifest <code>data.*</code>)</p><hr><h4 id="✅-2-7-—-security-hardening-tier-0-tier-1" tabindex="-1">✅ 2.7 — Security hardening, Tier 0 + Tier 1 <a class="header-anchor" href="#✅-2-7-—-security-hardening-tier-0-tier-1" aria-label="Permalink to &quot;✅ 2.7 — Security hardening, Tier 0 + Tier 1&quot;">​</a></h4><p><strong>Goal:</strong> Ship the no-crypto-machinery hardening tiers of RFC 0008 / SRS §3.17 in v1: security headers + threat-model doc (Tier 0) and transport hardening (Tier 1). At-rest encryption and beyond (Tiers 2–4) are deferred post-v1 to Task 1.0.01.</p><p><strong>Deliverables:</strong></p><ul><li>Tier 0: security headers (CSP/HSTS/X-Frame-Options/X-Content-Type-Options/Referrer-Policy/Permissions-Policy) in both Next configs + <code>runtime/middleware.ts</code>; cookie-hardening review; codify the no-telemetry guarantee; new <code>docs/security.md</code> (threat model + self-hoster hardening checklist)</li><li>Tier 1: Postgres <code>sslmode=require</code> + cert handling in <code>packages/db</code>; enforce TLS/HSTS at the edge (documented + required); optional shared-secret/mTLS on the internal runtime↔auth channel</li><li>No new app secrets or native deps in this task (those arrive with Tier 2 in Task 1.0.01)</li></ul><p><strong>Dependencies:</strong> none hard (TLS/HSTS doc assumes the reverse proxy already in <code>docs/self-hosting.md</code>)</p><p><strong>SRS reference:</strong> RFC 0008 (Tiers 0–1), SRS §3.17, NFR-02/07/08</p><p><strong>Review checklist:</strong></p><ul><li>Every response carries the security headers; CSP does not break the runtime/auth UIs or the inline theme script</li><li>Postgres connects over TLS when <code>sslmode=require</code>; <code>docs/security.md</code> documents the threat model and the hardening checklist</li><li>No behaviour change to the existing session/cookie flow</li></ul><hr><h4 id="✅-2-8-—-test-setup-seeding" tabindex="-1">✅ 2.8 — Test setup &amp; seeding <a class="header-anchor" href="#✅-2-8-—-test-setup-seeding" aria-label="Permalink to &quot;✅ 2.8 — Test setup &amp; seeding&quot;">​</a></h4><p><strong>Goal:</strong> A test-data foundation — in-code fixtures/factories plus an idempotent seed with per-role test users — and the dev/prod mode concept.</p><p><strong>Deliverables:</strong></p><ul><li>In-code fixtures/factories (user/tenant/plugin-status/notification) for unit/integration, placed per RFC 0010&#39;s layout</li><li><code>sv seed</code> (<code>scripts/seed.ts</code>): idempotent baseline data + per-role test users (admin, user; known passwords via <code>better-auth/crypto</code>), <strong>hard-gated to non-prod</strong></li><li>Document the disposable dev/test DB (config-only via <code>DATABASE_URL</code>/<code>AUTH_DATABASE_URL</code>); align with the RFC 0010 e2e tier; establish dev (default locally) vs prod mode</li></ul><p><strong>Dependencies:</strong> Task 0.5.16 (test-org layout)</p><p><strong>SRS reference:</strong> RFC 0019</p><p><strong>Review checklist:</strong></p><ul><li><code>sv seed</code> is idempotent and refuses to run against a prod DB; documented test users can log in</li><li>Fixtures need no running instance or DB</li></ul><hr><h4 id="✅-2-9-—-minimal-shell-mode" tabindex="-1">✅ 2.9 — Minimal shell mode <a class="header-anchor" href="#✅-2-9-—-minimal-shell-mode" aria-label="Permalink to &quot;✅ 2.9 — Minimal shell mode&quot;">​</a></h4><p><strong>Goal:</strong> Wire the third <code>shell</code> mode — <code>minimal</code> (chrome-free, full-bleed) — which currently fails the build.</p><p><strong>Deliverables:</strong></p><ul><li>A new top-level <code>(minimal)</code> route group (sibling of <code>(platform)</code>) with a committed chrome-free <code>layout.tsx</code> (force-dynamic for the CSP nonce; <code>100dvh</code> + safe-area per RFC 0013) + <code>.gitignore</code></li><li><code>generate-registry</code>: replace the <code>minimal</code> build-fail with a compose target (<code>(minimal)/&lt;routeSegment&gt;</code>, multi-segment allowed) + clear step; compose/parity tests</li><li>Root-plugin eligibility keeps minimal allowed (kiosk) with the no-chrome/no-nav caveat + a nav-contract convention documented; CLAUDE.md note</li></ul><p><strong>Dependencies:</strong> builds on the RFC 0001 composition model</p><p><strong>SRS reference:</strong> RFC 0014</p><p><strong>Review checklist:</strong></p><ul><li>A <code>shell: minimal</code> plugin composes to <code>(minimal)/</code> and renders chrome-free; the session gate still applies</li><li>It is not wrapped by the <code>(platform)</code> shell</li></ul><hr><h4 id="✅-2-10-—-mobile-responsiveness-pwa-hardening" tabindex="-1">✅ 2.10 — Mobile responsiveness &amp; PWA hardening <a class="header-anchor" href="#✅-2-10-—-mobile-responsiveness-pwa-hardening" aria-label="Permalink to &quot;✅ 2.10 — Mobile responsiveness &amp; PWA hardening&quot;">​</a></h4><p><strong>Goal:</strong> Harden the mobile and PWA experience across the three shell modes.</p><p><strong>Deliverables:</strong></p><ul><li>Default shell (mobile): footer → an action button opening a dismissable bottom <strong>Drawer</strong> (plugin nav); header gains the active-plugin title; Console moves into the avatar menu</li><li>Overlay: <code>--sv-dialog-inset-top</code> keeps the header visible above the mobile sheet</li><li>Cross-cutting: unify the 640/768 breakpoints; <code>100vh</code> → <code>100dvh</code>; <code>viewport-fit=cover</code> + <code>env(safe-area-inset-*)</code>; 44px touch targets + <code>--sv-touch-target-min</code>; manifest polish (<code>display_override</code>/<code>shortcuts</code>/<code>screenshots</code>/<code>orientation</code>, immersive iOS status bar)</li><li><code>packages/ui</code>: a <code>Drawer</code> primitive + tokens (additive <strong>minor</strong>); the first responsive section in <code>docs/design-system.md</code></li></ul><p><strong>Dependencies:</strong> relates to Task 0.5.24 (minimal safe-area)</p><p><strong>SRS reference:</strong> RFC 0013</p><p><strong>Review checklist:</strong></p><ul><li>The mobile footer opens the Drawer; an open overlay keeps the header visible; safe areas are respected in standalone</li><li>One documented breakpoint; the shell uses <code>dvh</code></li></ul><hr><h4 id="✅-2-11-—-offline-connectivity-banner" tabindex="-1">✅ 2.11 — Offline connectivity banner <a class="header-anchor" href="#✅-2-11-—-offline-connectivity-banner" aria-label="Permalink to &quot;✅ 2.11 — Offline connectivity banner&quot;">​</a></h4><p><strong>Goal:</strong> Surface connectivity status to users who are already in an authenticated session when their network drops. The hard-offline case (navigating to an uncached page) was already handled by the <code>/offline</code> fallback route; this task covers the soft-offline case — the network disappears while the user is on a page.</p><p><strong>Deliverables:</strong></p><ul><li><code>@sovereignfs/ui</code> → <strong>minor</strong> (0.7.0): status colour tokens — <code>--sv-color-warning-surface/text/border</code> (amber) and <code>--sv-color-success-surface/text/border</code> (green); backed by new <code>--sv-amber-*</code> / <code>--sv-green-*</code> primitive swatches; documented in <code>docs/design-system.md</code> &quot;Status colours&quot; section</li><li><code>runtime</code> → <strong>minor</strong> (0.20.0): <code>OfflineBanner</code> client component (<code>runtime/app/(platform)/_components/OfflineBanner.tsx</code>) — initialises to <code>&#39;online&#39;</code> server-safely (avoids SSR hydration mismatch), then checks <code>navigator.onLine</code> in <code>useEffect</code>; listens to <code>window</code> <code>offline</code>/<code>online</code> events; amber &quot;No internet connection&quot; banner persists until reconnected; green &quot;Back online&quot; flash auto-dismisses after 3 s (coincides with <code>reloadOnOnline</code> SW reload); <code>position: fixed; top: 0; z-index: 200</code> (above the mobile header&#39;s <code>z-index: 101</code>); 200 ms slide-in animation; uses <code>alert-triangle</code> icon and <code>--sv-color-warning-*</code> / <code>--sv-color-success-*</code> tokens</li><li>Wired into both <code>(platform)/layout.tsx</code> and <code>(minimal)/layout.tsx</code>; excluded from <code>/offline</code> (implicit there)</li><li><code>CLAUDE.md</code> gains the browser-API / <code>useState</code> hydration rule: never read <code>navigator</code>/<code>window</code>/<code>localStorage</code> in a <code>useState</code> initializer — initialise to a server-safe value and read in <code>useEffect</code></li></ul><p><strong>Dependencies:</strong> Task 0.5.01 (PWA — <code>reloadOnOnline</code>), Task 0.5.17 (Icon — <code>alert-triangle</code>), Task 0.5.25 (mobile shell — z-index context)</p><p><strong>SRS reference:</strong> SRS §3.11 (PWA)</p><p><strong>Review checklist:</strong></p><ul><li>DevTools → Network → Offline: amber banner slides in immediately; no hydration error in dev or production build</li><li>DevTools → Network → Online: green &quot;Back online&quot; flash appears then dismisses after ~3 s; page reloads from SW</li><li>Loading from SW cache while offline: amber banner present on mount (not deferred until a network event)</li><li>Mobile (&lt; 768 px): banner is above the sticky header; <code>z-index: 200</code> &gt; header&#39;s <code>101</code></li><li>Dark mode: dark amber/green tokens render correctly</li></ul><hr><h4 id="✅-2-12-—-production-dev-mode-diagnostics" tabindex="-1">✅ 2.12 — Production dev-mode &amp; diagnostics <a class="header-anchor" href="#✅-2-12-—-production-dev-mode-diagnostics" aria-label="Permalink to &quot;✅ 2.12 — Production dev-mode &amp; diagnostics&quot;">​</a></h4><p><strong>Goal:</strong> Validate features on a production instance against a mock database without touching real data, plus local no-telemetry diagnostics.</p><p><strong>Deliverables:</strong></p><ul><li>A request-scoped dev-mode switch (<code>AsyncLocalStorage</code>, never global) → the mock DB for the toggled request only; env-gated off by default, secret-authenticated, visibly flagged, audited (RFC 0005); the mock DB seeded by <code>sv seed</code></li><li>Resolve the auth-server mock-DB crux (or scope v1 to data-only mock)</li><li>Structured logging (<code>LOG_LEVEL</code>, stdout only) + a richer admin <code>/api/admin/health</code> — reconciled with the no-telemetry guarantee</li></ul><p><strong>Dependencies:</strong> Task 0.5.23 (seed), Task 0.5.12 (audit)</p><p><strong>SRS reference:</strong> RFC 0020</p><p><strong>Review checklist:</strong></p><ul><li>✅ A dev-mode request reads only the mock DB; concurrent real requests are unaffected; nothing egresses</li></ul><hr><h4 id="✅-2-13-—-sidebar-customization-—-plugin-ordering-and-visibility" tabindex="-1">✅ 2.13 — Sidebar customization — plugin ordering and visibility <a class="header-anchor" href="#✅-2-13-—-sidebar-customization-—-plugin-ordering-and-visibility" aria-label="Permalink to &quot;✅ 2.13 — Sidebar customization — plugin ordering and visibility&quot;">​</a></h4><p><strong>Goal:</strong> Let each user reorder and hide individual plugin icons in the sidebar&#39;s middle section (the plugin strip), without affecting the fixed chrome (notifications bell, console icon, account avatar) or the Launcher home icon.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/db</code> → <strong>patch</strong> (1.7.2): <code>sidebar_plugins</code> column (nullable <code>text</code>, JSON-serialised <code>Array&lt;{ id: string; hidden: boolean }&gt;</code>) added to <code>account_prefs</code> in both SQLite and Postgres schemas; <code>SidebarPluginEntry</code> type exported; <code>AccountPrefsValue</code> extended with <code>sidebarPlugins: SidebarPluginEntry[] | null</code>; <code>getAccountPrefs</code> / <code>setAccountPrefs</code> helpers updated; Drizzle-kit migration 0006 for both dialects</li><li><code>runtime</code> → <strong>minor</strong> (0.32.0): <code>/api/account/prefs</code> PATCH accepts <code>sidebar_plugins</code> (validated array or <code>null</code> to reset); new <code>GET /api/account/sidebar-plugins</code> returns available non-chrome plugin list and the user&#39;s current saved order (consumed by the Account preferences UI); <code>(platform)/layout.tsx</code> reads the authenticated user&#39;s saved preference server-side and merges it into <code>pluginList</code> — applying custom order and filtering hidden plugins — before rendering the sidebar and passing <code>pluginList</code> to <code>MobileNav</code></li><li><code>plugins/account</code> → <strong>minor</strong> (0.11.0): new <strong>Sidebar</strong> section on the Preferences page; <code>SidebarControl</code> client component — draggable list (HTML5 DnD, no extra dep), per-row show/hide toggle, reset-to-default button; <code>updateSidebarPluginsAction</code> server action calls <code>patchPrefs({ sidebar_plugins })</code></li></ul><p><strong>Constraints:</strong></p><ul><li>Launcher home icon stays pinned first in the sidebar and is not included in the customisation list</li><li>Chrome plugins (console, notifications, account avatar) are always fixed in the bottom section and excluded from the list</li></ul><p><strong>Dependencies:</strong> Tasks 2.1 (shell layout), 2.8 (account prefs infrastructure)</p><p><strong>Review checklist:</strong></p><ul><li>Account → Preferences → Sidebar section lists all installed non-chrome, non-launcher plugins</li><li>Dragging a plugin row to a new position and saving reflects in the sidebar on next load</li><li>Toggling a plugin hidden and saving removes its icon from the sidebar middle section; bottom chrome is unaffected</li><li>Hidden plugins remain visible in the Sidebar settings list so users can re-enable them</li><li>A newly installed plugin not yet in the saved list appears at the end of the sidebar by default</li><li>Mobile nav drawer reflects the same order and visibility as the desktop sidebar</li><li>A user with no saved preference sees the default install order (no regression)</li><li>Resetting to default clears the preference; sidebar reverts to install order</li><li><code>pnpm format:check</code>, <code>pnpm lint</code>, <code>pnpm typecheck</code>, <code>pnpm test</code> all pass</li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0001-overlay-shell-variant.html">RFC 0001 — Overlay shell variant</a></li><li><a href="./../rfcs/0002-cross-plugin-data-sharing.html">RFC 0002 — Cross-plugin data sharing</a></li><li><a href="./../rfcs/0008-security-encryption-architecture.html">RFC 0008 — Security &amp; encryption architecture</a></li><li><a href="./../rfcs/0013-mobile-responsiveness-pwa.html">RFC 0013 — Mobile responsiveness &amp; PWA</a></li><li><a href="./../rfcs/0014-minimal-shell-mode.html">RFC 0014 — Minimal shell mode</a></li><li><a href="./../rfcs/0019-test-setup-and-seeding.html">RFC 0019 — Test setup &amp; seeding</a></li><li><a href="./../rfcs/0020-production-dev-mode.html">RFC 0020 — Production dev-mode &amp; diagnostics</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../architecture.html">architecture.md</a></li><li><a href="./../architecture-rules.html">architecture-rules.md</a></li><li><a href="./../security.html">security.md</a></li><li><a href="./../plugin-development.html">plugin-development.md — Shell modes</a></li></ul>',123)])])}const g=o(r,[["render",n]]);export{h as __pageData,g as default};
